const jobs = [];

// Simulate job search results based on configuration
const positions = $node["Load Configuration"].json.positions;
const locations = $node["Load Configuration"].json.locations;

for (let i = 0; i < 5; i++) {
  jobs.push({
    id: i + 1,
    role: positions[0],
    company: `Company ${i + 1}`,
    location: locations[0],
    link: `https://example.com/job/${i + 1}`,
    description: `Job description for ${positions[0]} position at Company ${i + 1}`,
    apply_method: 'online'
  });
}

return { jobs };

const jobs = $node["Fetch Job Listings"].json.jobs;
const config = $node["Load Configuration"].json.config;

// Filter jobs based on blacklists
const filteredJobs = jobs.filter(job => {
  const companyBlacklist = config.company_blacklist || [];
  const titleBlacklist = config.title_blacklist || [];
  const locationBlacklist = config.location_blacklist || [];

  const companyBlocked = companyBlacklist.some(company => 
    job.company.toLowerCase().includes(company.toLowerCase())
  );
  const titleBlocked = titleBlacklist.some(title => 
    job.role.toLowerCase().includes(title.toLowerCase())
  );
  const locationBlocked = locationBlacklist.some(location => 
    job.location.toLowerCase().includes(location.toLowerCase())
  );

  return !companyBlocked && !titleBlocked && !locationBlocked;
});

return { filteredJobs, count: filteredJobs.length };

