const filteredJobs = $node["Filter Jobs by Blacklist"].json.filteredJobs;
const coverLetterResponse = $node["Generate Cover Letter"].json;
const resumeTailoringResponse = $node["Generate Resume Tailoring"].json;

const applications = [];

filteredJobs.forEach((job, index) => {
  applications.push({
    job_id: job.id,
    job_title: job.role,
    company: job.company,
    location: job.location,
    job_link: job.link,
    application_date: new Date().toISOString(),
    status: 'pending',
    resume_tailored: !!resumeTailoringResponse,
    cover_letter_generated: !!coverLetterResponse
  });
});

return { applications, total: applications.length };

const fs = require('fs');
const path = require('path');

const dataFolder = 'data_folder';
const outputFolder = path.join(dataFolder, 'output');
const applications = $node["Create Application Records"].json.applications;

if (!fs.existsSync(outputFolder)) {
  fs.mkdirSync(outputFolder, { recursive: true });
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const filename = `applications_${timestamp}.json`;
const filepath = path.join(outputFolder, filename);

fs.writeFileSync(filepath, JSON.stringify(applications, null, 2));

return {
  success: true,
  savedFile: filepath,
  applicationsCount: applications.length,
  message: `${applications.length} job applications recorded and saved.`
};

const result = $node["Save Application Results"].json;
