    total_applications: result.applicationsCount,
    saved_to: result.savedFile,
    positions_targeted: config.positions,
    locations_targeted: config.locations,
    experience_levels: config.experience_level,
    job_types: config.job_types,
    execution_time: new Date().toISOString()
  },
  message: result.message
};
